import React, { useState, useRef, useEffect } from 'react';
import MessageBubble from './MessageBubble';
import './ChatWindow.css';

function ChatWindow() {
  const [messages, setMessages] = useState([
    {
      sender: 'bot',
      text: 'Hello 👋 I am your AI assistant. How can I help you today?',
    },
  ]);

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);

  // 🔥 AUTO SCROLL REF
  const messagesEndRef = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg = { sender: 'user', text: input };
    const currentInput = input;
    setInput('');

    // add user message
    setMessages((prev) => [...prev, userMsg]);

    setIsTyping(true);

    try {
      const res = await fetch('http://127.0.0.1:8000/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: currentInput,
          history: messages.map((m) => [m.sender, m.text]),
        }),
      });

      const reader = res.body.getReader();
      const decoder = new TextDecoder();

      let botText = '';

      while (true) {
        const { value, done } = await reader.read();
        if (done) break;

        const chunk = decoder.decode(value);
        botText += chunk;

        setMessages((prev) => {
          const updated = [...prev];
          // if no bot message yet, create one
          if (updated[updated.length - 1]?.sender !== 'bot') {
            updated.push({ sender: 'bot', text: botText });
          } else {
            updated[updated.length - 1].text = botText;
          }
          return updated;
        });
      }
    } catch (err) {
      setMessages((prev) => [
        ...prev,
        { sender: 'bot', text: 'Error: backend unreachable.' },
      ]);
    }

    setIsTyping(false);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter') {
      handleSend();
    }
  };

  return (
    <div className="chat-window">
      {/* MESSAGES */}
      <div className="messages">
        {messages.map((msg, i) => (
          <MessageBubble key={i} text={msg.text} sender={msg.sender} />
        ))}

        {/* TYPING INDICATOR */}
        {isTyping && (
          <div className="message-row bot">
            <div className="typing-bubble">
              <span></span>
              <span></span>
              <span></span>
            </div>
          </div>
        )}

        {/* AUTO SCROLL TARGET */}
        <div ref={messagesEndRef} />
      </div>

      {/* INPUT */}
      <div className="input-area">
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={handleKeyPress}
          placeholder="Ask something..."
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
}

export default ChatWindow;
